	SELECT COUNT(*)
    FROM department
    WHERE dept_id = #{deptId}
      AND com_id = #{comId}

	SELECT *
    FROM department
    WHERE com_id = #{comId}
      AND dept_status = 'ACTIVE'
      AND dept_id != #{deptId}
      AND (
	 	 parent_id = (SELECT parent_id FROM department WHERE dept_id = #{deptId})  -- 형제 부서
      OR dept_id = (SELECT parent_id FROM department WHERE dept_id = #{deptId}) -- 상위 부서 자체
      )
        ORDER BY dept_name

	SELECT *
    FROM department
    WHERE com_id = #{comId}
      AND dept_status = 'ACTIVE'
      AND dept_id != #{deptId}
    ORDER BY dept_name

